mapper.insert:
/* com.matjzing.mapper.FrontMemberMapper.insertMember */
INSERT INTO MEMBER (
      MEMBER_TYPE_CD, ID, CI, DI, GENDER_CD, TELECOM_SECTION_CD, NATIVE_SECTION_CD
    , PASSWORD, PASSWORD_CHANGE_DT, NAME, NICKNAME, INTRODUCTION, MOBILE_PHONE_NO, EMAIL, BIRTHDAY
    , JOIN_DT, RECENT_LOGIN_DT, RECENT_CONNECTION_DT, MEMBER_STATUS_CD, MEMBER_STATUS_CHANGE_DT
    , LOGIN_FAILURE_COUNT, AUTO_LOGIN_YN, SERVICE_TERMS_AGREE_YN, SERVICE_TERMS_AGREE_DT
    , PERSONAL_INFO_USE_AGREE_YN, PERSONAL_INFO_USE_AGREE_DT, MARKETING_USE_AGREE_YN, MARKETING_USE_AGREE_DT
    , USE_YN, REGISTER_SEQ, REGISTER_IP, REGISTRATION_DT, UPDATER_SEQ, UPDATER_IP, UPDATE_DT
) VALUES (
      'EMAIL', #{id}, #{ci}, #{di}, #{genderCd}, #{telecomSectionCd}, #{nativeSectionCd}
    , #{password}, NOW(3), #{name}, #{nickname}, NULL, #{mobilePhoneNo}, #{email}, #{birthday}
    , NOW(3), NOW(3), NOW(3), 'NORMAL', NOW(3)
    , 0, FALSE, TRUE, NOW(3), TRUE, NOW(3), FALSE, NULL
    , TRUE, #{registerSeq}, #{registerIp}, COALESCE(#{registrationDt}, NOW(3)), #{updaterSeq}, #{updaterIp}, COALESCE(#{updateDt}, NOW(3))
)

/* com.matjzing.mapper.FrontMemberMapper.insertMemberGoogle */
INSERT INTO MEMBER (
      MEMBER_TYPE_CD, ID, CI, DI, GOOGLE_SUB, GENDER_CD, TELECOM_SECTION_CD, NATIVE_SECTION_CD
    , PASSWORD, PASSWORD_CHANGE_DT, NAME, NICKNAME, INTRODUCTION, MOBILE_PHONE_NO, EMAIL, BIRTHDAY
    , JOIN_DT, RECENT_LOGIN_DT, RECENT_CONNECTION_DT, MEMBER_STATUS_CD, MEMBER_STATUS_CHANGE_DT
    , LOGIN_FAILURE_COUNT, AUTO_LOGIN_YN, SERVICE_TERMS_AGREE_YN, SERVICE_TERMS_AGREE_DT
    , PERSONAL_INFO_USE_AGREE_YN, PERSONAL_INFO_USE_AGREE_DT, MARKETING_USE_AGREE_YN, MARKETING_USE_AGREE_DT
    , USE_YN, REGISTER_SEQ, REGISTER_IP, REGISTRATION_DT, UPDATER_SEQ, UPDATER_IP, UPDATE_DT
) VALUES (
      #{memberTypeCd}, #{id}, #{ci}, #{di}, #{googleSub}, #{genderCd}, #{telecomSectionCd}, #{nativeSectionCd}
    , #{password}, NOW(3), #{name}, #{nickname}, NULL, #{mobilePhoneNo}, #{email}, #{birthday}
    , NOW(3), NOW(3), NOW(3), 'NORMAL', NOW(3)
    , 0, FALSE, TRUE, NOW(3), TRUE, NOW(3), FALSE, NULL
    , TRUE, #{registerSeq}, #{registerIp}, COALESCE(#{registrationDt}, NOW(3)), #{updaterSeq}, #{updaterIp}, COALESCE(#{updateDt}, NOW(3))
)

mapper.select:
/* com.matjzing.mapper.FrontMemberMapper.checkId */
SELECT COUNT(*)
FROM MEMBER
WHERE USE_YN = TRUE
  AND ID = #{id}

mapper.update:
/* com.matjzing.mapper.FrontMemberMapper.deleteMember */
UPDATE MEMBER
SET UPDATER_SEQ = #{updaterSeq}
  , UPDATE_DT = NOW(3)
  , UPDATER_IP = #{updaterIp}
  , PASSWORD = #{password}
  , USE_YN = FALSE
WHERE MEMBER_SEQ = #{memberSeq}

mapper.select:
/* com.matjzing.mapper.FrontMemberMapper.selectMember */
SELECT ID, PASSWORD, DI, MEMBER_STATUS_CD
FROM MEMBER
WHERE USE_YN = TRUE
  AND MEMBER_SEQ = #{memberSeq}

